import{_ as t}from"./chunks/subs-support-page.Bdji-M7h.js";import{_ as r,o as a,c as n,a0 as s}from"./chunks/framework.jwovEGr5.js";const o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",f=JSON.parse('{"title":"Request a Subscription","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/request-subscription.md","filePath":"subscriptions/request-subscription.md"}'),i={name:"subscriptions/request-subscription.md"};function u(l,e,h,d,p,g){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="request-a-subscription" tabindex="-1">Request a Subscription <a class="header-anchor" href="#request-a-subscription" aria-label="Permalink to &quot;Request a Subscription&quot;">​</a></h1><p>If you want a premium <a href="./../getting-started/glossary.html#plan">plan</a> — more room, more features — you ask for it through the <strong>Support &amp; Plans</strong> page. Your request goes to a Supreme Admin, who reviews it and (once any payment is arranged) activates the plan.</p><p><strong>Who can request:</strong> Supreme Admin, King, Alliance Leader, and Co-Leader. Alliance Players can&#39;t send requests.</p><p><img src="'+t+'" alt="Support &amp; Plans page"></p><h2 id="sending-a-request" tabindex="-1">Sending a request <a class="header-anchor" href="#sending-a-request" aria-label="Permalink to &quot;Sending a request&quot;">​</a></h2><ol><li>Open <strong>Support &amp; Plans</strong> from the sidebar.</li><li>Browse the available premium plans and their features.</li><li>Fill in the request form: <ul><li><strong>For</strong> — whether the request is for a <strong>kingdom</strong> or an <strong>alliance</strong>, and which one.</li><li><strong>Plan</strong> — the premium plan you want (if relevant to the request type).</li><li><strong>Request type</strong> — see the guide below.</li><li><strong>Message</strong> — a note to the admin explaining what you need.</li></ul></li><li>Submit. Your request appears in <strong>My Requests</strong> with a status, and a message thread opens between you and the admin.</li></ol><p><img src="'+o+'" alt="Request detail with message thread"></p><h2 id="which-request-type-should-i-pick" tabindex="-1">Which request type should I pick? <a class="header-anchor" href="#which-request-type-should-i-pick" aria-label="Permalink to &quot;Which request type should I pick?&quot;">​</a></h2><p>The form asks for a <strong>request type</strong>. Pick the one that matches your situation:</p><table tabindex="0"><thead><tr><th>Choose…</th><th>When you want to…</th></tr></thead><tbody><tr><td><strong>New subscription</strong></td><td>Start premium for a kingdom or alliance that&#39;s currently on the free tier.</td></tr><tr><td><strong>Upgrade</strong></td><td>Move from one plan to a higher one (for example, add features you don&#39;t have yet).</td></tr><tr><td><strong>Quota increase</strong></td><td>Stay on your plan but ask for a higher limit on something you&#39;re running out of (players, storage, etc.).</td></tr><tr><td><strong>Premium processing interest</strong></td><td>Register interest in the &quot;Premium Processing&quot; feature, which is <strong>coming soon</strong>. This flags that you&#39;d want it — it doesn&#39;t turn anything on today.</td></tr><tr><td><strong>Other</strong></td><td>Anything that doesn&#39;t fit the above. Explain it in your message.</td></tr></tbody></table><p>If you&#39;re not sure, <strong>New subscription</strong> (for going premium) or <strong>Quota increase</strong> (for &quot;I just need more room&quot;) cover most cases. When in doubt, pick the closest one and describe the details in your message — the admin can adjust.</p><h2 id="what-happens-after-you-submit" tabindex="-1">What happens after you submit <a class="header-anchor" href="#what-happens-after-you-submit" aria-label="Permalink to &quot;What happens after you submit&quot;">​</a></h2><p>Your request moves through a few states. You&#39;ll see the current one on the request, and the admin drives the changes:</p><ul><li><strong>Pending</strong> — waiting for the admin to look at it.</li><li><strong>Awaiting payment</strong> — the admin sent you payment instructions. See <a href="./payment-instructions.html">Payment Instructions</a>.</li><li><strong>Completed</strong> — the plan has been activated. Your <a href="./effective-plan.html">effective plan</a> updates and premium features unlock.</li><li><strong>Rejected</strong> — the admin declined; the reason is usually in the thread.</li><li><strong>Cancelled</strong> — you (or the admin) called it off.</li></ul><p>You can <strong>reply</strong> in the thread at any time to ask questions or confirm details, and you can <strong>cancel</strong> a request you no longer need.</p><h2 id="tracking-your-requests" tabindex="-1">Tracking your requests <a class="header-anchor" href="#tracking-your-requests" aria-label="Permalink to &quot;Tracking your requests&quot;">​</a></h2><p>The <strong>My Requests</strong> list shows every request you&#39;ve made and its status. Open any one to read the full thread, see payment instructions, reply, or cancel.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./payment-instructions.html">Payment Instructions</a> — how payment is arranged (it&#39;s manual).</li><li><a href="./premium-features.html">Premium Features</a> — what you&#39;ll unlock.</li><li>Prefer to get premium from your King instead? See <a href="./accept-grant.html">Accept a Premium Offer</a>.</li></ul>',19)])])}const y=r(i,[["render",u]]);export{f as __pageData,y as default};
